import{_ as s,o as e,c as n,ae as i}from"./chunks/framework.BIONGpTb.js";const u=JSON.parse('{"title":"个人电脑作为服务器","description":"","frontmatter":{},"headers":[],"relativePath":"服务器/个人电脑作为局域网服务器.md","filePath":"服务器/个人电脑作为局域网服务器.md"}'),t={name:"服务器/个人电脑作为局域网服务器.md"};function l(p,a,o,c,d,r){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="个人电脑作为服务器" tabindex="-1">个人电脑作为服务器 <a class="header-anchor" href="#个人电脑作为服务器" aria-label="Permalink to &quot;个人电脑作为服务器&quot;">​</a></h1><p>这里使用到的主要是 linux、docker、nginx</p><h2 id="linux的安装" tabindex="-1">linux的安装 <a class="header-anchor" href="#linux的安装" aria-label="Permalink to &quot;linux的安装&quot;">​</a></h2><ol><li>在官方下载长期支持的版本之后，使用烧录工具将下载好的光盘文件烧录到u盘中</li><li>在高级启动选项中选择重启</li><li>插入u盘使用u盘安装ubantu</li><li>安装ubuntu</li><li>设置好之后，重启，选择ubuntu启动</li></ol><h2 id="docker安装" tabindex="-1">docker安装 <a class="header-anchor" href="#docker安装" aria-label="Permalink to &quot;docker安装&quot;">​</a></h2><p>docker是什么？ Docker 是一个开源的应用容器引擎，基于 Go 语言 并遵从 Apache2.0 协议开源。 Docker 可以让开发者打包他们的应用以及依赖包到一个轻量级、可移植的容器中，然后发布到任何流行的 Linux 机器上，也可以实现虚拟化。 容器是完全使用沙箱机制，相互之间不会有任何接口（类似 iPhone 的 app）,更重要的是容器性能开销极低。</p><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><ol><li>更新apt工具和索引</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get update</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt-get install \\ca-certificates \\curl \\gnupg \\lsb-release</span></span></code></pre></div><ol start="2"><li>添加docker官方gpg密钥</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -fsSL https://mirrors.aliyun.com/docker-ce/linux/ubuntu/gpg | sudo gpg --dearmor -o /usr/share/keyrings/docker-archive-keyring.gpg</span></span></code></pre></div><ol start="3"><li>添加docker软件源</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>echo &quot;deb [arch=$(dpkg --print-architecture) signed-by=/usr/share/keyrings/docker-archive-keyring.gpg] https://mirrors.aliyun.com/docker-ce/linux/ubuntu $(lsb_release -cs) stable&quot; | sudo tee /etc/apt/sources.list.d/docker.list &gt; /dev/null</span></span></code></pre></div><ol start="4"><li>更新索引包，安装docker</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo systemctl daemon-reload</span></span>
<span class="line"><span>sudo systemctl restart docker</span></span></code></pre></div><ol start="5"><li>验证：检查docker服务状态</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo systemctl status docker</span></span></code></pre></div><p>如果显示running就没问题</p><h2 id="拉取nginx镜像" tabindex="-1">拉取nginx镜像 <a class="header-anchor" href="#拉取nginx镜像" aria-label="Permalink to &quot;拉取nginx镜像&quot;">​</a></h2><p>用docker取拉取nginx镜像，这里由于很多镜像源都失效了，所以使用了渡渡鸟镜像</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo docker pull swr.cn-north-4.myhuaweicloud.com/ddn-k8s/registry.k8s.io/nginx-slim:0.21</span></span></code></pre></div><p>后面的是从渡渡鸟镜像上复制下来的，根据镜像不同要更改</p><p>执行启动命令</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo docker run -d \\</span></span>
<span class="line"><span>  --name my-nginx \\</span></span>
<span class="line"><span>  -p 80:80 \\</span></span>
<span class="line"><span>  -v ~/my-website:/usr/share/nginx/html \\</span></span>
<span class="line"><span>  swr.cn-north-4.myhuaweicloud.com/ddn-k8s/registry.k8s.io/nginx-slim:0.21</span></span></code></pre></div><p>现在在本地访问localhost，就能看到网页</p><h2 id="部署自己的网页" tabindex="-1">部署自己的网页 <a class="header-anchor" href="#部署自己的网页" aria-label="Permalink to &quot;部署自己的网页&quot;">​</a></h2><ol><li>将文件夹准备好，获取到完整路径。比如：<code>/home/kfjr/web-test</code></li><li>重新挂载目录</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo docker stop my-nginx</span></span>
<span class="line"><span>sudo docker rm my-nginx</span></span></code></pre></div><ol start="3"><li>启动新的容器,这里使用<code>/home/kfjr/web-test</code>来演示，实际服务时替换成自己的就行</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo docker run -d \\</span></span>
<span class="line"><span>  --name my-nginx \\</span></span>
<span class="line"><span>  -p 80:80 \\</span></span>
<span class="line"><span>  -v /home/kfjr/web-test:/usr/share/nginx/html \\</span></span>
<span class="line"><span>  swr.cn-north-4.myhuaweicloud.com/ddn-k8s/registry.k8s.io/nginx-slim:0.21</span></span></code></pre></div><p>这里会返回一串哈希值，然后你可以看到已经部署的网页了</p><h2 id="在同一个局域网下访问" tabindex="-1">在同一个局域网下访问 <a class="header-anchor" href="#在同一个局域网下访问" aria-label="Permalink to &quot;在同一个局域网下访问&quot;">​</a></h2><p>拿到ip地址 使用命令<code>ip a</code>找到wlan0里的inet 例如：192.168.1.105 然后在同一个局域网下能看到这个网页</p><h3 id="学到了什么" tabindex="-1">学到了什么 <a class="header-anchor" href="#学到了什么" aria-label="Permalink to &quot;学到了什么&quot;">​</a></h3><p>对工程化有了一点点概念，为什么要工程化？工程化打包之后减少了体积，同时更好的部署</p>`,36)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
